export function getOrphanetDiseases(): KnowledgeEntry[] {
  const entries: KnowledgeEntry[] = [];

  for (const d of diseases) {
    entries.push({
      source: "orphanet",
      title: `${d.name} (ORPHA:${d.orphaCode}) — Présentation clinique`,
      content: `${d.name} (code Orphanet : ORPHA:${d.orphaCode}). Prévalence : ${d.prevalence}. Transmission : ${d.inheritance}. Âge de début : ${d.ageOfOnset}.\n\nSignes cliniques : ${d.symptoms}`,
      metadata: {
        orphaCode: d.orphaCode,
        disease: d.name,
        prevalence: d.prevalence,
        inheritance: d.inheritance,
        language: "fr",
        type: "rare_disease",
        section: "clinical_presentation",
      },
    });

    entries.push({
      source: "orphanet",
      title: `${d.name} (ORPHA:${d.orphaCode}) — Diagnostic et prise en charge`,
      content: `Critères diagnostiques de ${d.name} : ${d.diagnosticCriteria}\n\nPrise en charge : ${d.management}`,
      metadata: {
        orphaCode: d.orphaCode,
        disease: d.name,
        language: "fr",
        type: "rare_disease",
        section: "diagnosis_management",
      },
    });
  }

  return entries;
}
